/**
 * User Module Types
 *
 * Type definitions for the User module including:
 * - User entity types
 * - CRUD DTOs
 * - Role assignment types
 * - Profile management types
 * - Event payloads
 * - Query filters
 *
 * @module modules/_core/user/types
 *
 * @example
 * ```typescript
 * import type {
 *   User,
 *   CreateUserRequest,
 *   UpdateProfileRequest,
 * } from '@/modules/_core/user/user.types';
 *
 * async function createUser(data: CreateUserRequest): Promise<User> { ... }
 * ```
 */

import type { UserStatus, RoleScope } from '@prisma/client';

// -----------------------------------------------------------------------------
// Core Entity Types
// -----------------------------------------------------------------------------

/**
 * User entity from Prisma
 */
export interface User {
  /** Unique identifier (CUID) */
  id: string;
  /** User email (unique) */
  email: string;
  /** Hashed password */
  passwordHash: string;
  /** First name */
  firstName: string;
  /** Last name */
  lastName: string;
  /** Avatar URL (optional) */
  avatar: string | null;
  /** Phone number (optional) */
  phone: string | null;
  /** User status */
  status: UserStatus;
  /** Email verification timestamp */
  emailVerifiedAt: Date | null;
  /** Last login timestamp */
  lastLoginAt: Date | null;
  /** Organization ID (null for platform users) */
  organizationId: string | null;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * User without sensitive data (password hash)
 */
export interface SafeUser extends Omit<User, 'passwordHash'> {
  /** Full name (computed) */
  fullName: string;
}

/**
 * User with related data
 */
export interface UserWithRelations extends User {
  /** Associated organization */
  organization?: {
    id: string;
    name: string;
    slug: string;
  } | null;
  /** User roles */
  userRoles?: UserRoleInfo[];
  /** Role count */
  _count?: {
    userRoles: number;
    sessions: number;
  };
}

/**
 * User role information
 */
export interface UserRoleInfo {
  /** Role ID */
  roleId: string;
  /** Role name */
  role: {
    id: string;
    name: string;
    displayName: string;
    scope: RoleScope;
  };
  /** Assignment date */
  assignedAt: Date;
}

// -----------------------------------------------------------------------------
// Profile Types
// -----------------------------------------------------------------------------

/**
 * User profile for display purposes
 */
export interface UserProfile {
  /** User ID */
  id: string;
  /** Email address */
  email: string;
  /** First name */
  firstName: string;
  /** Last name */
  lastName: string;
  /** Full name */
  fullName: string;
  /** Avatar URL */
  avatar: string | null;
  /** Phone number */
  phone: string | null;
  /** Email verified status */
  isEmailVerified: boolean;
  /** User roles */
  roles: string[];
  /** Organization info (if applicable) */
  organization?: {
    id: string;
    name: string;
    slug: string;
  } | null;
  /** Account created date */
  createdAt: Date;
}

// -----------------------------------------------------------------------------
// Request/Response Types
// -----------------------------------------------------------------------------

/**
 * Create user request
 */
export interface CreateUserRequest {
  /** User email */
  email: string;
  /** Password (plain text, will be hashed) */
  password: string;
  /** First name */
  firstName: string;
  /** Last name */
  lastName: string;
  /** Phone number (optional) */
  phone?: string;
  /** Organization ID (optional, null for platform users) */
  organizationId?: string | null;
  /** Initial role IDs to assign */
  roleIds?: string[];
  /** Whether to send invitation email */
  sendInvite?: boolean;
}

/**
 * Create user response
 */
export interface CreateUserResponse {
  /** Created user (without password) */
  user: SafeUser;
  /** Whether invitation was sent */
  inviteSent: boolean;
  /** Success message */
  message: string;
}

/**
 * Update user request
 */
export interface UpdateUserRequest {
  /** First name */
  firstName?: string;
  /** Last name */
  lastName?: string;
  /** Phone number */
  phone?: string | null;
  /** Avatar URL */
  avatar?: string | null;
}

/**
 * Update user response
 */
export interface UpdateUserResponse {
  /** Updated user */
  user: SafeUser;
  /** Success message */
  message: string;
}

/**
 * Update profile request (self-update)
 */
export interface UpdateProfileRequest {
  /** First name */
  firstName?: string;
  /** Last name */
  lastName?: string;
  /** Phone number */
  phone?: string | null;
  /** Avatar URL */
  avatar?: string | null;
}

/**
 * Update profile response
 */
export interface UpdateProfileResponse {
  /** Updated profile */
  profile: UserProfile;
  /** Success message */
  message: string;
}

/**
 * Change password request
 */
export interface ChangePasswordRequest {
  /** Current password */
  currentPassword: string;
  /** New password */
  newPassword: string;
  /** Confirm new password */
  confirmPassword: string;
}

/**
 * Change password response
 */
export interface ChangePasswordResponse {
  /** Success message */
  message: string;
}

/**
 * Change user status request
 */
export interface ChangeStatusRequest {
  /** New status */
  status: UserStatus;
  /** Reason for status change (for audit) */
  reason?: string;
}

/**
 * Change user status response
 */
export interface ChangeStatusResponse {
  /** Updated user */
  user: SafeUser;
  /** Previous status */
  previousStatus: UserStatus;
  /** Success message */
  message: string;
}

/**
 * Assign role request
 */
export interface AssignRoleRequest {
  /** Role ID to assign */
  roleId: string;
}

/**
 * Assign role response
 */
export interface AssignRoleResponse {
  /** User ID */
  userId: string;
  /** Role ID */
  roleId: string;
  /** Success message */
  message: string;
}

/**
 * Remove role request
 */
export interface RemoveRoleRequest {
  /** Role ID to remove */
  roleId: string;
}

/**
 * Remove role response
 */
export interface RemoveRoleResponse {
  /** User ID */
  userId: string;
  /** Role ID */
  roleId: string;
  /** Success message */
  message: string;
}

/**
 * User summary for listings
 */
export interface UserSummary {
  /** User ID */
  id: string;
  /** Email */
  email: string;
  /** Full name */
  fullName: string;
  /** Avatar URL */
  avatar: string | null;
  /** User status */
  status: UserStatus;
  /** Primary role */
  primaryRole?: string;
  /** Role count */
  roleCount: number;
  /** Last login date */
  lastLoginAt: Date | null;
  /** Creation date */
  createdAt: Date;
}

/**
 * Invite user request
 */
export interface InviteUserRequest {
  /** Email to invite */
  email: string;
  /** First name */
  firstName: string;
  /** Last name */
  lastName: string;
  /** Role ID to assign */
  roleId: string;
}

/**
 * Invite user response
 */
export interface InviteUserResponse {
  /** Created user */
  user: SafeUser;
  /** Success message */
  message: string;
}

// -----------------------------------------------------------------------------
// Query/Filter Types
// -----------------------------------------------------------------------------

/**
 * User list query filters
 */
export interface UserListFilters {
  /** Filter by status */
  status?: UserStatus;
  /** Filter by role ID */
  roleId?: string;
  /** Search by name or email */
  search?: string;
  /** Filter by email verified */
  emailVerified?: boolean;
  /** Filter by creation date range */
  createdAfter?: Date;
  createdBefore?: Date;
  /** Include soft-deleted */
  includeDeleted?: boolean;
}

/**
 * User list query params
 */
export interface UserListParams extends UserListFilters {
  /** Page number (1-indexed) */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'email' | 'firstName' | 'lastName' | 'createdAt' | 'lastLoginAt' | 'status';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * User created event payload
 */
export interface UserCreatedEvent {
  /** User ID */
  userId: string;
  /** User email */
  email: string;
  /** Organization ID (if applicable) */
  organizationId: string | null;
  /** Creator user ID */
  createdBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * User updated event payload
 */
export interface UserUpdatedEvent {
  /** User ID */
  userId: string;
  /** Changed fields */
  changes: Partial<User>;
  /** User who made the change */
  updatedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * User deleted event payload
 */
export interface UserDeletedEvent {
  /** User ID */
  userId: string;
  /** User email (for reference) */
  email: string;
  /** Organization ID */
  organizationId: string | null;
  /** User who deleted */
  deletedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * User status changed event payload
 */
export interface UserStatusChangedEvent {
  /** User ID */
  userId: string;
  /** Previous status */
  previousStatus: UserStatus;
  /** New status */
  newStatus: UserStatus;
  /** Reason for change */
  reason?: string;
  /** User who made the change */
  changedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Role assigned event payload
 */
export interface RoleAssignedEvent {
  /** User ID */
  userId: string;
  /** Role ID */
  roleId: string;
  /** Role name */
  roleName: string;
  /** User who assigned the role */
  assignedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Role removed event payload
 */
export interface RoleRemovedEvent {
  /** User ID */
  userId: string;
  /** Role ID */
  roleId: string;
  /** Role name */
  roleName: string;
  /** User who removed the role */
  removedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Password changed event payload
 */
export interface PasswordChangedEvent {
  /** User ID */
  userId: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Profile updated event payload
 */
export interface ProfileUpdatedEvent {
  /** User ID */
  userId: string;
  /** Changed fields */
  changes: Partial<User>;
  /** Event timestamp */
  timestamp: string;
}

// -----------------------------------------------------------------------------
// Hook Context Types
// -----------------------------------------------------------------------------

/**
 * Before create hook context
 */
export interface BeforeCreateContext {
  /** Create request data */
  data: CreateUserRequest;
  /** User creating the user */
  userId?: string;
  /** Organization ID */
  organizationId?: string;
}

/**
 * After create hook context
 */
export interface AfterCreateContext {
  /** Created user */
  user: User;
  /** User who created the user */
  userId?: string;
}

/**
 * Before update hook context
 */
export interface BeforeUpdateContext {
  /** User ID */
  userId: string;
  /** Update request data */
  data: UpdateUserRequest;
  /** User making the update */
  updatedBy?: string;
}

/**
 * After update hook context
 */
export interface AfterUpdateContext {
  /** Updated user */
  user: User;
  /** Previous values */
  previousData: User;
  /** User who made the update */
  updatedBy?: string;
}

// -----------------------------------------------------------------------------
// Module Settings Types
// -----------------------------------------------------------------------------

/**
 * User module settings
 */
export interface UserModuleSettings {
  /** Default role for new users */
  defaultRole: string;
  /** Require email verification */
  requireEmailVerification: boolean;
  /** Allow self-registration */
  allowSelfRegistration: boolean;
  /** Maximum users per organization */
  maxUsersPerOrg: number;
  /** Minimum password length */
  passwordMinLength: number;
  /** Require uppercase in password */
  passwordRequireUppercase: boolean;
  /** Require numbers in password */
  passwordRequireNumbers: boolean;
  /** Session max age in milliseconds */
  sessionMaxAge: number;
}

// -----------------------------------------------------------------------------
// Type Guards
// -----------------------------------------------------------------------------

/**
 * Type guard to check if an object is a valid User
 */
export function isUser(obj: unknown): obj is User {
  return (
    typeof obj === 'object' &&
    obj !== null &&
    'id' in obj &&
    'email' in obj &&
    'firstName' in obj &&
    'lastName' in obj &&
    'status' in obj
  );
}

/**
 * Type guard to check if an object is a valid SafeUser
 */
export function isSafeUser(obj: unknown): obj is SafeUser {
  return isUser(obj) && 'fullName' in obj && !('passwordHash' in obj);
}

// -----------------------------------------------------------------------------
// Helper Functions
// -----------------------------------------------------------------------------

/**
 * Converts a User to a SafeUser (removes passwordHash)
 */
export function toSafeUser(user: User): SafeUser {
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const { passwordHash, ...safeFields } = user;
  return {
    ...safeFields,
    fullName: `${user.firstName} ${user.lastName}`.trim(),
  };
}

/**
 * Converts a User to a UserProfile
 */
export function toUserProfile(
  user: User,
  roles: string[] = [],
  organization?: { id: string; name: string; slug: string } | null
): UserProfile {
  return {
    id: user.id,
    email: user.email,
    firstName: user.firstName,
    lastName: user.lastName,
    fullName: `${user.firstName} ${user.lastName}`.trim(),
    avatar: user.avatar,
    phone: user.phone,
    isEmailVerified: user.emailVerifiedAt !== null,
    roles,
    organization,
    createdAt: user.createdAt,
  };
}
